module top_module(
    adder,
    address,
    rst,
    clk,
);input clk;
input rst;
input [15:0] adder;
output [7:0] address;
reg   [15:0] decrementer;
assign address[7:0] = decrementer[15:8];
always @(posedge clk or posedge rst) begin
    if (rst) begin
        decrementer <= 0;
    end
    else
    begin
        decrementer <= decrementer + adder;    
    end
end
endmodule
